  1→// UK formatting utilities
  2→
  3→/**
  4→ * Safely convert any value into a renderable string.
  5→ * Handles Firestore Timestamps ({_seconds, _nanoseconds}),
  6→ * Date objects, strings, numbers, null/undefined, and plain objects.
  7→ * Prevents React Error #310 ("Objects are not valid as a React child").
  8→ */
  9→export function safeText(value: any, fallback = 'N/A'): string {
 10→  if (value === null || value === undefined) return fallback;
 11→  if (typeof value === 'string') return value || fallback;
