  1→import { useMemo } from 'react';
  2→import { allCases, repairs, complaints, dampMouldCases } from '@/data';
  3→import { formatCurrency } from '@/utils/format';
  4→import type { Tenant, Property, Repair, Complaint } from '@/types';
  5→
  6→export interface AiField {
  7→  label: string;
  8→  value: string;
  9→  source: string;
 10→  severity?: 'info' | 'warning' | 'critical';
 11→}
 12→
 13→export interface EntityIntelligence {
 14→  urgencyLevel: 'normal' | 'attention' | 'urgent' | 'crisis';
 15→  pageAccentColour: string;
 16→  prioritySections: string[];
 17→  expandedSections: string[];
 18→  dynamicFields: AiField[];
