 21→}
 22→
 23→export function useTenantIntelligence(tenant: Tenant | undefined, tenantCases?: any[]): EntityIntelligence {
 24→  return useMemo(() => {
 25→    if (!tenant) return defaultIntelligence();
 26→
 27→    const fields: AiField[] = [];
 28→    const warnings: string[] = [];
 29→    const emphasis: Record<string, 'highlight' | 'pulse' | 'dim'> = {};
 30→    let urgency: 'normal' | 'attention' | 'urgent' | 'crisis' = 'normal';
 31→    const prioritySections: string[] = [];
 32→    const expandedSections: string[] = [];
 33→
 34→    // Estimated household income
 35→    const bedrooms = 2; // Default
 36→    const baseIncome = tenant.ucStatus === 'claiming' ? 14000 : tenant.ucStatus === 'transitioning' ? 16000 : 24000;
 37→    const estimatedIncome = baseIncome + (tenant.household.filter(m => !m.isDependent).length * 8000);
 38→    fields.push({
 39→      label: 'Estimated Household Income',
 40→      value: formatCurrency(estimatedIncome) + '/year',
 41→      source: `Derived from tenure type, household composition, UC status (${tenant.ucStatus || 'N/A'})`,
 42→      severity: estimatedIncome < 16000 ? 'warning' : 'info',
 43→    });
 44→
 45→    // Complaint risk
 46→    const openRepairs = (tenantCases || allCases.filter(c => c.tenantId === tenant.id))
 47→      .filter(c => c.type === 'repair' && c.status !== 'completed').length;
 48→    const contactFrequency = tenant.contactCount30Days || 0;
 49→    let complaintRisk = 0;
 50→    if (openRepairs > 2) complaintRisk += 30;
 51→    if (openRepairs > 0 && contactFrequency > 3) complaintRisk += 25;
 52→    if (tenant.rentBalance < -500) complaintRisk += 15;
 53→    if (contactFrequency > 5) complaintRisk += 20;
 54→    const existingComplaint = allCases.filter(c => c.tenantId === tenant.id && c.type === 'complaint' && c.status !== 'closed').length > 0;
 55→    if (existingComplaint) complaintRisk += 10;
 56→    complaintRisk = Math.min(complaintRisk, 99);
 57→
 58→    if (complaintRisk > 40) {
 59→      fields.push({
 60→        label: 'Complaint Risk',
 61→        value: complaintRisk >= 70 ? 'HIGH' : complaintRisk >= 50 ? 'MEDIUM' : 'LOW',
 62→        source: `${openRepairs} open repairs, ${contactFrequency} contacts in 30 days`,
 63→        severity: complaintRisk >= 70 ? 'critical' : complaintRisk >= 50 ? 'warning' : 'info',
 64→      });
 65→    }
 66→
 67→    // Arrears trajectory
 68→    if (tenant.rentBalance < 0) {
 69→      const weeklyGap = tenant.weeklyCharge * 0.3; // Estimated
 70→      fields.push({
 71→        label: 'Arrears Trajectory',
 72→        value: tenant.arrearsRisk > 60 ? `Increasing — est. ${formatCurrency(weeklyGap)}/week gap` : 'Stable — payments covering charges',
 73→        source: 'Based on 12-week payment pattern analysis',
 74→        severity: tenant.arrearsRisk > 60 ? 'critical' : 'warning',
 75→      });
 76→      emphasis['rentBalance'] = tenant.arrearsRisk > 70 ? 'pulse' : 'highlight';
 77→    }
 78→
 79→    // Tenancy sustainability score
 80→    const sustainabilityScore = Math.max(0, 100 - (tenant.arrearsRisk * 0.4) - (complaintRisk * 0.3) - (tenant.vulnerabilityFlags.length * 5));
 81→    fields.push({
 82→      label: 'Tenancy Sustainability Score',
 83→      value: `${Math.round(sustainabilityScore)}/100`,
 84→      source: 'Composite: arrears risk, complaint risk, vulnerability factors',
 85→      severity: sustainabilityScore < 40 ? 'critical' : sustainabilityScore < 60 ? 'warning' : 'info',
 86→    });
 87→
 88→    // Determine urgency level
 89→    if (complaintRisk >= 70 || tenant.arrearsRisk >= 80 || tenant.vulnerabilityFlags.some(f => f.severity === 'high')) {
 90→      urgency = 'crisis';
 91→      prioritySections.push('cases');
 92→      expandedSections.push('cases');
 93→      warnings.push('This tenant requires immediate attention — multiple risk factors detected.');
 94→    } else if (complaintRisk >= 50 || tenant.arrearsRisk >= 60 || tenant.rentBalance < -500) {
 95→      urgency = 'urgent';
 96→      prioritySections.push('cases', 'statement');
 97→    } else if (openRepairs > 0 || tenant.rentBalance < 0) {
 98→      urgency = 'attention';
 99→    }
100→
101→    // Vulnerability-based warnings
102→    if (tenant.vulnerabilityFlags.length > 0) {
103→      const highSeverity = tenant.vulnerabilityFlags.filter(f => f.severity === 'high');
104→      if (highSeverity.length > 0) {
105→        warnings.push(`High-severity vulnerability: ${highSeverity.map(f => f.type).join(', ')}. Ensure communications are appropriate.`);
106→      }
107→    }
108→
109→    // Silent tenant warning
110→    if (tenant.lastContact) {
111→      const parts = tenant.lastContact.split('/');
112→      const lastDate = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
113→      const daysSinceContact = Math.ceil((new Date(2026, 1, 7).getTime() - lastDate.getTime()) / (1000 * 60 * 60 * 24));
114→      if (daysSinceContact > 180) {
115→        fields.push({
116→          label: 'Silent Tenant Alert',
117→          value: `${daysSinceContact} days since last contact`,
118→          source: 'No inbound or outbound contact recorded',
119→          severity: 'warning',
120→        });
121→        warnings.push(`No contact for ${daysSinceContact} days. Welfare check recommended.`);
122→      }
123→    }
124→
125→    return {
126→      urgencyLevel: urgency,
127→      pageAccentColour: urgency === 'crisis' ? 'brand-garnet' : urgency === 'urgent' ? 'status-warning' : urgency === 'attention' ? 'brand-blue' : 'brand-teal',
128→      prioritySections,
129→      expandedSections,
130→      dynamicFields: fields,
131→      dynamicWarnings: warnings,
132→      visualEmphasis: emphasis,
133→    };
134→  }, [tenant?.id]);
135→}
