154→      fields.push({ label: 'Estimated Retrofit Cost to EPC C', value: formatCurrency(cost), source: `Current rating ${property.epc.rating} (SAP ${property.epc.sapScore})`, severity: property.epc.rating >= 'E' ? 'warning' : 'info' });
155→    }
