176→    }
177→
178→    return {
179→      urgencyLevel: urgency,
180→      pageAccentColour: urgency === 'crisis' ? 'brand-garnet' : urgency === 'urgent' ? 'status-warning' : 'brand-teal',
181→      prioritySections: urgency === 'crisis' ? ['compliance'] : [],
182→      expandedSections: urgency === 'crisis' ? ['compliance'] : [],
183→      dynamicFields: fields,
