  1→import { Router } from 'express';
  2→import { collections, getDocs, getDoc, setDoc, updateDoc } from '../services/firestore.js';
  3→import { authMiddleware } from '../middleware/auth.js';
  4→import type { CaseDoc, ActivityDoc } from '../models/firestore-schemas.js';
