  9→/** Parse date strings in DD/MM/YYYY or YYYY-MM-DD format to epoch ms for sorting */
 10→function parseFlexDate(dateStr: string | undefined): number {
 11→  if (!dateStr) return 0;
 12→  // DD/MM/YYYY format (UK)
 13→  const ukMatch = dateStr.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
 14→  if (ukMatch) {
 15→    return new Date(`${ukMatch[3]}-${ukMatch[2]}-${ukMatch[1]}`).getTime() || 0;
 16→  }
 17→  // ISO YYYY-MM-DD or full ISO string
 18→  const ts = new Date(dateStr).getTime();
 19→  return isNaN(ts) ? 0 : ts;
 20→}
 21→
 22→// GET /api/v1/cases?type=repair&status=open&handler=Sarah+Mitchell&priority=emergency
 23→casesRouter.get('/', async (req, res, next) => {
 24→  try {
 25→    const { type, status, handler, priority, propertyId, tenantId, limit: limitStr, offset: offsetStr } = req.query;
 26→    const limit = limitStr ? parseInt(limitStr as string, 10) : 50;
 27→    const offset = offsetStr ? parseInt(offsetStr as string, 10) : 0;
 28→
 29→    // Fetch all cases (no composite index needed), then filter + sort in memory.
 30→    // With ~300 cases this is fast and avoids Firestore composite index requirements.
 31→    let cases = await getDocs<CaseDoc>(collections.cases, undefined, undefined, 1000);
 32→
 33→    // Apply filters in memory
 34→    if (type) cases = cases.filter(c => c.type === type);
 35→    if (status) cases = cases.filter(c => c.status === status);
 36→    if (handler) cases = cases.filter(c => c.handler === handler);
 37→    if (priority) cases = cases.filter(c => c.priority === priority);
 38→    if (propertyId) cases = cases.filter(c => c.propertyId === propertyId);
 39→    if (tenantId) cases = cases.filter(c => c.tenantId === tenantId);
 40→
 41→    // Sort by createdDate descending — handles both DD/MM/YYYY and YYYY-MM-DD formats
 42→    cases.sort((a, b) => {
 43→      const dateA = parseFlexDate(a.createdDate);
 44→      const dateB = parseFlexDate(b.createdDate);
 45→      return dateB - dateA;
 46→    });
 47→
 48→    const total = cases.length;
 49→    const totalPages = Math.ceil(total / limit);
 50→    const page = Math.floor(offset / limit) + 1;
 51→
 52→    // Apply pagination
 53→    cases = cases.slice(offset, offset + limit);
 54→
 55→    res.json({
 56→      items: cases,
