 22→
 23→// Static data imports for fallback
 24→import {
 25→  regions as staticRegions,
 26→  localAuthorities as staticLAs,
 27→  estates as staticEstates,
 28→  blocks as staticBlocks,
 29→  properties as staticProperties,
 30→  tenants as staticTenants,
 31→  allCases as staticCases,
 32→  allRepairs as staticRepairs,
 33→  allComplaints as staticComplaints,
 34→  allDampCases as staticDampCases,
 35→  asbCases as staticAsbCases,
 36→  activities as staticActivities,
 37→  communications as staticComms,
 38→  voidProperties as staticVoids,
 39→  applicants as staticApplicants,
 40→  tsmMeasures as staticTsm,
 41→  organisation as staticOrg,
 42→} from '../data';
