 56→// ---- Config ----
 57→// Check if the API is available. If fetch fails, fallback to static.
 58→let apiAvailable: boolean | null = null;
 59→
 60→async function checkApiAvailability(): Promise<boolean> {
 61→  if (apiAvailable !== null) return apiAvailable;
 62→  try {
 63→    const res = await fetch('/health', { method: 'GET' });
 64→    apiAvailable = res.ok;
 65→  } catch {
 66→    apiAvailable = false;
 67→  }
 68→  return apiAvailable;
 69→}
 70→
 71→// Wrapper that tries API first, falls back to static data
 72→async function withFallback<T>(apiFn: () => Promise<T>, staticData: T): Promise<T> {
 73→  const available = await checkApiAvailability();
 74→  if (!available) return staticData;
 75→  try {
 76→    return await apiFn();
 77→  } catch {
 78→    return staticData;
 79→  }
 80→}
 81→
 82→// ---- Explore Hooks ----
 83→export function useExploreHierarchy(level?: string, parentId?: string) {
 84→  return useQuery({
 85→    queryKey: ['explore', 'hierarchy', level, parentId],
 86→    queryFn: () => withFallback(
 87→      () => exploreApi.hierarchy(level, parentId),
 88→      buildStaticHierarchy(level, parentId)
 89→    ),
 90→  });
 91→}
 92→
 93→function buildStaticHierarchy(level?: string, parentId?: string) {
 94→  if (!level) {
 95→    return { level: 'country', children: staticRegions };
 96→  }
 97→  switch (level) {
 98→    case 'region':
 99→      return { level: 'region', parentId, children: staticLAs.filter(la => la.regionId === parentId) };
100→    case 'local-authority':
101→      return { level: 'local-authority', parentId, children: staticEstates.filter(e => e.localAuthorityId === parentId) };
102→    case 'estate':
103→      return { level: 'estate', parentId, children: staticBlocks.filter(b => b.estateId === parentId) };
104→    case 'block':
105→      return { level: 'block', parentId, children: staticProperties.filter(p => p.blockId === parentId) };
106→    default:
107→      return { level: level || 'unknown', children: [] };
108→  }
109→}
