465→// ---- Static data filter helpers ----
466→function filterStatic<T extends Record<string, any>>(
467→  data: T[],
468→  filters?: Record<string, string | undefined>,
469→): T[] {
470→  if (!filters) return data;
471→  return data.filter(item => {
472→    return Object.entries(filters).every(([key, value]) => {
473→      if (value === undefined || value === '') return true;
474→      return String(item[key]) === value;
475→    });
476→  });
477→}
478→
479→function filterStaticCases(filters?: Record<string, string | undefined>) {
480→  let cases: any[] = staticCases;
481→  if (!filters) return cases;
482→  if (filters.type) {
483→    switch (filters.type) {
484→      case 'repair': cases = staticRepairs as any[]; break;
485→      case 'complaint': cases = staticComplaints as any[]; break;
486→      case 'damp-mould': cases = staticDampCases as any[]; break;
487→      case 'asb': cases = staticAsbCases as any[]; break;
488→      default: cases = staticCases.filter(c => c.type === filters.type);
489→    }
490→  }
491→  return filterStatic(cases, { ...filters, type: undefined });
492→}
