 11→/**
 12→ * Recursively walk a JSON value and convert Firestore Timestamp objects
 13→ * into locale date strings so React components never receive raw objects
 14→ * as children (prevents Error #310).
 15→ *
 16→ * Handles both formats:
 17→ *   - {_seconds, _nanoseconds}   (older @google-cloud/firestore)
 18→ *   - {seconds, nanoseconds}     (newer @google-cloud/firestore)
 19→ *
 20→ * Also catches any remaining plain objects that somehow made it through
 21→ * server-side serialisation, converting them to "[object]" strings
 22→ * rather than crashing React.
 23→ */
 24→function sanitizeFirestoreTimestamps(value: any): any {
 25→  if (value === null || value === undefined) return value;
 26→  if (typeof value !== 'object') return value;
 27→  if (Array.isArray(value)) return value.map(sanitizeFirestoreTimestamps);
 28→
 29→  const keys = Object.keys(value);
 30→
 31→  // Firestore Timestamp — underscore variant {_seconds, _nanoseconds}
 32→  if ('_seconds' in value && '_nanoseconds' in value && keys.length <= 3) {
 33→    try {
 34→      return new Date(value._seconds * 1000).toLocaleDateString('en-GB');
 35→    } catch {
 36→      return 'N/A';
 37→    }
 38→  }
 39→
 40→  // Firestore Timestamp — public variant {seconds, nanoseconds}
 41→  if (
 42→    'seconds' in value &&
 43→    'nanoseconds' in value &&
 44→    typeof value.seconds === 'number' &&
 45→    keys.length <= 3
 46→  ) {
 47→    try {
 48→      return new Date(value.seconds * 1000).toLocaleDateString('en-GB');
 49→    } catch {
 50→      return 'N/A';
 51→    }
 52→  }
 53→
 54→  // Recurse into plain objects
 55→  const out: Record<string, any> = {};
 56→  for (const key of keys) {
 57→    out[key] = sanitizeFirestoreTimestamps(value[key]);
 58→  }
 59→  return out;
 60→}
