 62→async function request<T>(path: string, options?: RequestInit): Promise<T> {
 63→  const url = `${API_BASE}${path}`;
 64→  const persona = localStorage.getItem('socialhomes-persona') || 'housing-officer';
 65→  const authMode = localStorage.getItem('socialhomes-auth-mode');
 66→
 67→  // Build auth headers: Firebase JWT if authenticated, otherwise X-Persona
 68→  const authHeaders: Record<string, string> = {};
 69→  if (authMode === 'firebase') {
 70→    const token = await getIdToken();
 71→    if (token) {
 72→      authHeaders['Authorization'] = `Bearer ${token}`;
 73→    }
 74→  }
 75→  // Always include X-Persona as fallback (server uses it when no Bearer token)
 76→  authHeaders['X-Persona'] = persona;
 77→
 78→  const response = await fetch(url, {
 79→    ...options,
 80→    headers: {
 81→      'Content-Type': 'application/json',
 82→      ...authHeaders,
 83→      ...options?.headers,
 84→    },
 85→  });
 86→
 87→  if (!response.ok) {
 88→    const error = await response.json().catch(() => ({ error: response.statusText }));
 89→    throw new Error(error.error || `API error: ${response.status}`);
 90→  }
 91→
 92→  const data = await response.json();
 93→  return sanitizeFirestoreTimestamps(data) as T;
 94→}
