 96→function buildQueryString(params: Record<string, string | number | boolean | undefined>): string {
 97→  const entries = Object.entries(params).filter(([, v]) => v !== undefined && v !== '');
 98→  if (entries.length === 0) return '';
 99→  return '?' + entries.map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`).join('&');
100→}
