// ============================================================
// SocialHomes.Ai — Complete Type Definitions
// ============================================================

// ---- Personas ----
export type Persona = 'coo' | 'head-of-service' | 'manager' | 'housing-officer' | 'operative';

export interface User {
  id: string;
  name: string;
  email: string;
  role: string;
  persona: Persona;
  avatar?: string;
  team?: string;
  patch?: string;
}

// ---- Geography / Hierarchy ----
export interface Region {
  id: string;
  name: string;
  lat: number;
  lng: number;
  localAuthorities: string[];
  totalUnits: number;
  compliance: number;
  arrears: number;
  voids: number;
}

export interface LocalAuthority {
  id: string;
  name: string;
  regionId: string;
  lat: number;
  lng: number;
  estates: string[];
  totalUnits: number;
  compliance: number;
  lhaRates?: Record<string, number>;
}

export interface Estate {
  id: string;
  name: string;
  localAuthorityId: string;
  postcode: string;
  lat: number;
  lng: number;
  constructionEra: string;
  totalUnits: number;
  blocks: string[];
  schemeType: 'general-needs' | 'sheltered' | 'extra-care' | 'supported' | 'mixed';
  managingOfficer: string;
  occupancy: number;
  compliance: number;
  dampCases: number;
  arrears: number;
  asbCases: number;
  repairsBacklog: number;
  // External API enrichment fields
  lsoaCodes?: string[];
  crimeCount30Days?: number;
  crimeCountPrevious30Days?: number;
  crimeTrend?: 'up' | 'down' | 'stable';
}

export interface Block {
  id: string;
  name: string;
  estateId: string;
  address: string;
  uprn: string;
  lat: number;
  lng: number;
  constructionType: string;
  constructionYear: number;
  storeys: number;
  totalUnits: number;

