import { useState, useEffect, useRef, useCallback } from 'react';
import { X, CheckCircle, Loader2, AlertCircle } from 'lucide-react';

export interface ActionField {
  id: string;
  label: string;
  type: 'text' | 'textarea' | 'select' | 'date' | 'readonly';
  placeholder?: string;
  options?: { value: string; label: string }[];
  defaultValue?: string;
  required?: boolean;
}

interface ActionModalProps {
  open: boolean;
  onClose: () => void;
  title: string;
  description?: string;
  icon?: React.ReactNode;
  fields: ActionField[];
  submitLabel?: string;
  onSubmit: (values: Record<string, string>) => void | Promise<void>;
  variant?: 'default' | 'success' | 'warning' | 'danger';
}

export default function ActionModal({ open, onClose, title, description, icon, fields, submitLabel = 'Submit', onSubmit, variant = 'default' }: ActionModalProps) {
  const [values, setValues] = useState<Record<string, string>>(() => {
    const defaults: Record<string, string> = {};
    fields.forEach(f => { if (f.defaultValue) defaults[f.id] = f.defaultValue; });
    return defaults;
  });
  const [submitted, setSubmitted] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const modalRef = useRef<HTMLDivElement>(null);
  const previousFocusRef = useRef<HTMLElement | null>(null);

  // Store the previously focused element and focus the modal when opened
  useEffect(() => {
    if (open) {
      previousFocusRef.current = document.activeElement as HTMLElement;
      // Focus the modal after animation
      requestAnimationFrame(() => {
        modalRef.current?.focus();
      });
    } else {
      // Restore focus when closing
      previousFocusRef.current?.focus();
    }
  }, [open]);

  // Escape key handler
  useEffect(() => {
    if (!open) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        onClose();
      }
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [open, onClose]);

  // Focus trap
  useEffect(() => {
    if (!open || !modalRef.current) return;
    const modal = modalRef.current;
    const handleTab = (e: KeyboardEvent) => {
      if (e.key !== 'Tab') return;
      const focusable = modal.querySelectorAll<HTMLElement>(
        'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
      );
      if (focusable.length === 0) return;
      const first = focusable[0];
      const last = focusable[focusable.length - 1];
      if (e.shiftKey && document.activeElement === first) {
        e.preventDefault();
        last.focus();
      } else if (!e.shiftKey && document.activeElement === last) {
        e.preventDefault();
        first.focus();
      }
    };
    document.addEventListener('keydown', handleTab);
    return () => document.removeEventListener('keydown', handleTab);
  }, [open]);

  const validate = useCallback(() => {
    const newErrors: Record<string, string> = {};
    fields.forEach(field => {
      if (field.required && field.type !== 'readonly') {
        const val = values[field.id]?.trim();
        if (!val) {
          newErrors[field.id] = `${field.label} is required`;
        }
      }
    });
    return newErrors;
  }, [fields, values]);

  const handleBlur = (fieldId: string) => {
    setTouched(prev => ({ ...prev, [fieldId]: true }));
    const field = fields.find(f => f.id === fieldId);
    if (field?.required && !values[fieldId]?.trim()) {
      setErrors(prev => ({ ...prev, [fieldId]: `${field.label} is required` }));
    } else {
      setErrors(prev => {
        const next = { ...prev };
        delete next[fieldId];
        return next;
      });
    }
  };

  if (!open) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    // Validate all fields
    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      setTouched(Object.fromEntries(fields.map(f => [f.id, true])));
      return;
    }
    setSubmitting(true);
    try {
      await onSubmit(values);
      setSubmitting(false);
      setSubmitted(true);
      setTimeout(() => {
        setSubmitted(false);
        onClose();
      }, 1200);
    } catch (err) {
      setSubmitting(false);
      setErrors({ _form: err instanceof Error ? err.message : 'An error occurred. Please try again.' });
    }
  };

  const borderColor = variant === 'danger' ? 'border-status-critical/30' :
    variant === 'warning' ? 'border-status-warning/30' :
    variant === 'success' ? 'border-status-compliant/30' :
    'border-brand-teal/30';

  const fieldErrorClass = 'border-status-critical focus:border-status-critical';

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" role="presentation">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} aria-hidden="true" />

      {/* Modal */}
      <div
        ref={modalRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby="modal-title"
        aria-describedby={description ? 'modal-description' : undefined}
        tabIndex={-1}
        className={`relative bg-surface-card rounded-xl border ${borderColor} shadow-2xl w-full max-w-lg max-h-[80vh] overflow-y-auto animate-fade-in-up focus:outline-none`}
        style={{ animationDuration: '200ms' }}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-border-default">
          <div className="flex items-center gap-3">
            {icon}
            <div>
              <h2 id="modal-title" className="text-lg font-bold text-text-primary">{title}</h2>
              {description && <p id="modal-description" className="text-xs text-text-muted mt-0.5">{description}</p>}
            </div>
          </div>
          <button onClick={onClose} className="p-2 rounded-lg hover:bg-surface-elevated transition-colors" aria-label="Close dialog">
            <X size={18} className="text-text-muted" />
          </button>
        </div>

        {/* Success State */}
        {submitted ? (
          <div className="p-8 text-center" role="status" aria-live="polite">
            <CheckCircle size={48} className="mx-auto text-status-compliant mb-3" />
            <h3 className="text-lg font-bold text-text-primary mb-1">Action Completed</h3>
            <p className="text-sm text-text-muted">Changes have been saved successfully.</p>
          </div>
        ) : (
          <form onSubmit={handleSubmit} noValidate>
            <div className="p-5 space-y-4">
              {errors._form && (
                <div className="flex items-center gap-2 p-3 bg-status-critical/10 border border-status-critical/20 rounded-lg text-sm text-status-critical" role="alert">
                  <AlertCircle size={16} />
                  {errors._form}
                </div>
              )}
              {fields.map(field => {
                const fieldId = `field-${field.id}`;
                const errorId = `error-${field.id}`;
                const hasError = touched[field.id] && errors[field.id];
                return (
                  <div key={field.id}>
                    <label htmlFor={fieldId} className="block text-xs text-text-muted uppercase tracking-wider mb-1.5 font-medium">
                      {field.label}{field.required && <span className="text-status-critical ml-0.5" aria-label="required">*</span>}
                    </label>
                    {field.type === 'readonly' ? (
                      <div id={fieldId} className="px-3 py-2 bg-surface-elevated rounded-lg text-sm text-text-secondary border border-border-default" aria-readonly="true">
                        {field.defaultValue}
                      </div>
                    ) : field.type === 'textarea' ? (
                      <textarea
                        id={fieldId}
                        className={`w-full px-3 py-2 bg-surface-elevated rounded-lg text-sm text-text-primary border ${hasError ? fieldErrorClass : 'border-border-default focus:border-brand-teal'} focus:outline-none resize-y min-h-[80px]`}
                        placeholder={field.placeholder}
                        value={values[field.id] || ''}
                        onChange={e => setValues(prev => ({ ...prev, [field.id]: e.target.value }))}
                        onBlur={() => handleBlur(field.id)}
                        aria-required={field.required}
                        aria-invalid={hasError ? 'true' : undefined}
                        aria-describedby={hasError ? errorId : undefined}
                      />
                    ) : field.type === 'select' ? (
                      <select
                        id={fieldId}
                        className={`w-full px-3 py-2 bg-surface-elevated rounded-lg text-sm text-text-primary border ${hasError ? fieldErrorClass : 'border-border-default focus:border-brand-teal'} focus:outline-none`}
                        value={values[field.id] || ''}
                        onChange={e => setValues(prev => ({ ...prev, [field.id]: e.target.value }))}
                        onBlur={() => handleBlur(field.id)}
                        aria-required={field.required}
                        aria-invalid={hasError ? 'true' : undefined}
                        aria-describedby={hasError ? errorId : undefined}
                      >
                        <option value="">Select...</option>
                        {field.options?.map(opt => (
                          <option key={opt.value} value={opt.value}>{opt.label}</option>
                        ))}
                      </select>
                    ) : (
                      <input
                        id={fieldId}
                        type={field.type}
                        className={`w-full px-3 py-2 bg-surface-elevated rounded-lg text-sm text-text-primary border ${hasError ? fieldErrorClass : 'border-border-default focus:border-brand-teal'} focus:outline-none`}
                        placeholder={field.placeholder}
                        value={values[field.id] || ''}
                        onChange={e => setValues(prev => ({ ...prev, [field.id]: e.target.value }))}
                        onBlur={() => handleBlur(field.id)}
                        aria-required={field.required}
                        aria-invalid={hasError ? 'true' : undefined}
                        aria-describedby={hasError ? errorId : undefined}
                      />
                    )}
                    {hasError && (
                      <div id={errorId} className="flex items-center gap-1 mt-1 text-xs text-status-critical" role="alert">
                        <AlertCircle size={12} />
                        {errors[field.id]}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>

            {/* Footer */}
            <div className="flex items-center justify-end gap-3 p-5 border-t border-border-default">
              <button type="button" onClick={onClose} className="px-4 py-2 text-sm text-text-muted bg-surface-elevated rounded-lg hover:bg-surface-hover transition-colors border border-border-default">
                Cancel
              </button>
              <button
                type="submit"
                disabled={submitting}
                className={`px-4 py-2 text-sm text-white rounded-lg transition-colors flex items-center gap-2 ${
                  variant === 'danger' ? 'bg-status-critical hover:bg-status-critical/80' :
                  variant === 'warning' ? 'bg-status-warning hover:bg-status-warning/80' :
                  variant === 'success' ? 'bg-status-compliant hover:bg-status-compliant/80' :
                  'bg-brand-teal hover:bg-brand-teal/80'
                } disabled:opacity-50`}
              >
                {submitting && <Loader2 size={14} className="animate-spin" />}
                {submitLabel}
              </button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
}

// UK formatting utilities

/**
 * Safely convert any value into a renderable string.
 * Handles Firestore Timestamps ({_seconds, _nanoseconds}),
 * Date objects, strings, numbers, null/undefined, and plain objects.
 * Prevents React Error #310 ("Objects are not valid as a React child").
 */
export function safeText(value: any, fallback = 'N/A'): string {
  if (value === null || value === undefined) return fallback;
  if (typeof value === 'string') return value || fallback;
  if (typeof value === 'number') return String(value);
  if (typeof value === 'boolean') return value ? 'Yes' : 'No';
  // Firestore Timestamp serialised via JSON (comes from Express API)
  if (typeof value === 'object' && '_seconds' in value) {
    try {
      const d = new Date(value._seconds * 1000);
      return d.toLocaleDateString('en-GB'); // DD/MM/YYYY
    } catch {
      return fallback;
    }
  }
  // Native Date object
  if (value instanceof Date) {
    return value.toLocaleDateString('en-GB');
  }
  // Firestore Timestamp with toDate() (if used client-side)
  if (typeof value === 'object' && typeof value.toDate === 'function') {
    try {
      return value.toDate().toLocaleDateString('en-GB');
    } catch {
      return fallback;
    }
  }
  // Fallback: stringify to prevent Error #310
  try {
    return JSON.stringify(value);
  } catch {
    return fallback;
  }
}

export function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('en-GB', {
    style: 'currency',
    currency: 'GBP',
    minimumFractionDigits: 2,
  }).format(amount);
}

export function formatNumber(n: number): string {
  return new Intl.NumberFormat('en-GB').format(n);
}

export function formatPercent(n: number, decimals = 1): string {
  return `${n.toFixed(decimals)}%`;
}

export function formatDate(dateStr: any): string {
  if (!dateStr) return 'N/A';
  // Firestore Timestamp serialised as JSON {_seconds, _nanoseconds}
  if (typeof dateStr === 'object' && '_seconds' in dateStr) {
    try { return new Date(dateStr._seconds * 1000).toLocaleDateString('en-GB'); } catch { return 'N/A'; }
  }
  // Firestore Timestamp with toDate()
  if (typeof dateStr === 'object' && typeof dateStr.toDate === 'function') {
    try { return dateStr.toDate().toLocaleDateString('en-GB'); } catch { return 'N/A'; }
  }
  // Native Date
  if (dateStr instanceof Date) {
    return dateStr.toLocaleDateString('en-GB');
  }
  // String — Already DD/MM/YYYY, return as-is
  if (typeof dateStr === 'string') {
    if (/^\d{2}\/\d{2}\/\d{4}$/.test(dateStr)) return dateStr;
    const d = new Date(dateStr);
    return isNaN(d.getTime()) ? String(dateStr) : d.toLocaleDateString('en-GB');
  }
  return String(dateStr);
}

function toDateObj(dateStr: any): Date {
  if (!dateStr) return new Date(NaN);
  if (typeof dateStr === 'object' && '_seconds' in dateStr) return new Date(dateStr._seconds * 1000);
  if (typeof dateStr === 'object' && typeof dateStr.toDate === 'function') return dateStr.toDate();
  if (dateStr instanceof Date) return dateStr;
  if (typeof dateStr === 'string' && /^\d{2}\/\d{2}\/\d{4}$/.test(dateStr)) {
    const parts = dateStr.split('/');
    return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
  }
  return new Date(dateStr);
}

export function daysUntil(dateStr: any): number {
  const target = toDateObj(dateStr);
  const now = new Date(2026, 1, 9); // Current date: 09/02/2026
  return Math.ceil((target.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
}

export function daysSince(dateStr: any): number {
  const target = toDateObj(dateStr);
  const now = new Date(2026, 1, 9);
  return Math.ceil((now.getTime() - target.getTime()) / (1000 * 60 * 60 * 24));
}

export function workingDaysUntil(dateStr: any): number {
  const target = toDateObj(dateStr);
  const now = new Date(2026, 1, 9);
  let count = 0;
  const current = new Date(now);
  while (current < target) {
    current.setDate(current.getDate() + 1);
    const day = current.getDay();
    if (day !== 0 && day !== 6) count++;
  }
  return count;
}

export function getTimerColour(daysRemaining: number, totalDays: number): string {
  const ratio = daysRemaining / totalDays;
  if (ratio > 0.5) return 'text-status-compliant';
  if (ratio > 0.2) return 'text-status-warning';
  if (daysRemaining > 0) return 'text-status-critical';
  return 'text-status-critical animate-pulse-critical';
}

export function getStatusColour(status: string): string {
  const map: Record<string, string> = {
    'compliant': 'bg-status-compliant/20 text-status-compliant',
    'valid': 'bg-status-compliant/20 text-status-compliant',
    'within': 'bg-status-compliant/20 text-status-compliant',
    'expiring': 'bg-status-warning/20 text-status-warning',
    'approaching': 'bg-status-warning/20 text-status-warning',
    'non-compliant': 'bg-status-critical/20 text-status-critical',
    'expired': 'bg-status-critical/20 text-status-critical',
    'breached': 'bg-status-critical/20 text-status-critical',
    'overdue': 'bg-status-critical/20 text-status-critical',
    'void': 'bg-status-void/20 text-status-void',
    'completed': 'bg-status-info/20 text-status-info',
    'closed': 'bg-status-void/20 text-status-void',
    'open': 'bg-brand-blue/20 text-brand-blue',
    'in-progress': 'bg-brand-teal/20 text-brand-teal',
    'investigation': 'bg-status-warning/20 text-status-warning',
    'response-due': 'bg-status-critical/20 text-status-critical',
    'awaiting-parts': 'bg-status-warning/20 text-status-warning',
    'monitoring': 'bg-status-info/20 text-status-info',
    'escalated': 'bg-status-critical/20 text-status-critical',
    'emergency': 'bg-status-critical/20 text-status-critical',
    'assigned': 'bg-brand-teal/20 text-brand-teal',
  };
  return map[status] || 'bg-status-void/20 text-status-void';
}

export function getCaseTypeColour(type: string): string {
  const map: Record<string, string> = {
    'complaint': 'border-l-orange-500',
    'repair': 'border-l-brand-blue',
    'asb': 'border-l-status-critical',
    'enquiry': 'border-l-status-void',
    'financial': 'border-l-status-warning',
    'safeguarding': 'border-l-status-ai',
    'damp-mould': 'border-l-brand-teal',
  };
  return map[type] || 'border-l-status-void';
}

export function truncate(str: string, len: number): string {
  return str.length > len ? str.substring(0, len) + '...' : str;
}

export function getInitials(name: string): string {
  return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
}

