import { chromium } from 'playwright';

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1440, height: 900 } });
  const baseUrl = 'http://localhost:4174';
  const screenshotDir = '/mnt/c/.netapps/socialhomes/test-screenshots';

  // Helper to wait for page load
  const waitForApp = async () => {
    await page.waitForTimeout(2000); // SPA hydration
  };

  console.log('=== REPAIR DETAIL PAGE TEST ===\n');

  // 1. Navigate to a repair detail page (rep-001 is in-progress, has high recurrence risk)
  console.log('1. Navigating to repair detail page (rep-001)...');
  await page.goto(`${baseUrl}/repairs/rep-001`);
  await waitForApp();
  await page.screenshot({ path: `${screenshotDir}/01-repair-detail-full.png`, fullPage: true });
  console.log('   Screenshot saved: 01-repair-detail-full.png');

  // 2. Check header elements
  const reference = await page.textContent('h1');
  console.log(`   Reference: ${reference}`);
  const statusPill = await page.locator('[class*="StatusPill"], [class*="status"]').first().textContent();
  console.log(`   Status visible: ${statusPill}`);

  // 3. Check tabs exist
  const tabButtons = await page.locator('button').filter({ hasText: /^(Details|Costs|Linked|Activity)$/ }).all();
  console.log(`\n2. Tabs found: ${tabButtons.length}`);
  for (const tab of tabButtons) {
    console.log(`   - ${await tab.textContent()}`);
  }

  // 4. Check sidebar sections
  const sidebarTenant = await page.locator('text=Tenant').first().isVisible();
  const sidebarProperty = await page.locator('text=Property').first().isVisible();
  const sidebarOfficer = await page.locator('text=Assigned Officer').first().isVisible();
  console.log(`\n3. Sidebar sections:`);
  console.log(`   Tenant: ${sidebarTenant}`);
  console.log(`   Property: ${sidebarProperty}`);
  console.log(`   Assigned Officer: ${sidebarOfficer}`);

  // 5. Check "Handler" is NOT present (should be "Assigned Officer")
  const handlerText = await page.locator('text=Handler').count();
  console.log(`\n4. "Handler" occurrences (should be 0): ${handlerText}`);

  // 6. Check AI Status Banner
  const aiBanner = await page.locator('[class*="border-status-ai"]').count();
  console.log(`\n5. AI Status Banner present: ${aiBanner > 0}`);

  // 7. Check vulnerability flags in sidebar
  const vulnFlags = await page.locator('text=Vulnerability Flags').count();
  console.log(`   Vulnerability Flags section: ${vulnFlags > 0}`);

  // 8. Check damp risk
  const dampRisk = await page.locator('text=Damp Risk Score').count();
  console.log(`   Damp Risk Score: ${dampRisk > 0}`);

  // 9. Click Costs tab
  console.log('\n6. Clicking Costs tab...');
  await page.locator('button').filter({ hasText: 'Costs' }).click();
  await page.waitForTimeout(500);
  await page.screenshot({ path: `${screenshotDir}/02-costs-tab.png`, fullPage: true });
  const labourSection = await page.locator('text=Labour Log').count();
  const partsSection = await page.locator('text=Parts Log').count();
  console.log(`   Labour Log section: ${labourSection > 0}`);
  console.log(`   Parts Log section: ${partsSection > 0}`);

  // 10. Click Linked tab
  console.log('\n7. Clicking Linked tab...');
  await page.locator('button').filter({ hasText: 'Linked' }).click();
  await page.waitForTimeout(500);
  await page.screenshot({ path: `${screenshotDir}/03-linked-tab.png`, fullPage: true });
  const createLinkedBtn = await page.locator('text=Create Linked Repair').count();
  const raiseComplaintBtn = await page.locator('text=Raise Complaint').count();
  const duplicateBtn = await page.locator('text=Duplicate').count();
  console.log(`   Create Linked Repair button: ${createLinkedBtn > 0}`);
  console.log(`   Raise Complaint button: ${raiseComplaintBtn > 0}`);
  console.log(`   Duplicate button: ${duplicateBtn > 0}`);

  // 11. Click Activity tab
  console.log('\n8. Clicking Activity tab...');
  await page.locator('button').filter({ hasText: 'Activity' }).click();
  await page.waitForTimeout(500);
  await page.screenshot({ path: `${screenshotDir}/04-activity-tab.png`, fullPage: true });

  // 12. Check Smart Action Bar
  console.log('\n9. Smart Action Bar...');
  const primaryBtn = await page.locator('text=Mark Complete').count(); // rep-001 is in-progress
  const moreActionsBtn = await page.locator('text=More Actions').count();
  console.log(`   Primary action "Mark Complete" (for in-progress): ${primaryBtn > 0}`);
  console.log(`   "More Actions" dropdown: ${moreActionsBtn > 0}`);

  // 13. Click More Actions to see dropdown
  if (moreActionsBtn > 0) {
    await page.locator('text=More Actions').click();
    await page.waitForTimeout(300);
    await page.screenshot({ path: `${screenshotDir}/05-more-actions-dropdown.png`, fullPage: true });
    const escalateOption = await page.locator('text=Escalate').count();
    const logLabourOption = await page.locator('text=Log Labour').count();
    const logPartsOption = await page.locator('text=Log Parts').count();
    console.log(`   Dropdown options - Escalate: ${escalateOption > 0}, Log Labour: ${logLabourOption > 0}, Log Parts: ${logPartsOption > 0}`);
  }

  // 14. Test an open repair (rep-004) to verify primary action changes
  console.log('\n10. Checking open repair (rep-004) primary action...');
  await page.goto(`${baseUrl}/repairs/rep-004`);
  await waitForApp();
  const triageBtn = await page.locator('text=Triage & Assign').count();
  console.log(`   Primary action "Triage & Assign" (for open): ${triageBtn > 0}`);
  await page.screenshot({ path: `${screenshotDir}/06-open-repair.png`, fullPage: true });

  // 15. Test a completed repair (rep-006) to verify Close & Review
  console.log('\n11. Checking completed repair (rep-006) primary action...');
  await page.goto(`${baseUrl}/repairs/rep-006`);
  await waitForApp();
  const closeReviewBtn = await page.locator('text=Close & Review').count();
  console.log(`   Primary action "Close & Review" (for completed): ${closeReviewBtn > 0}`);
  await page.screenshot({ path: `${screenshotDir}/07-completed-repair.png`, fullPage: true });

  // 16. Test Awaab's Law repair (rep-002)
  console.log('\n12. Checking Awaab\'s Law repair (rep-002)...');
  await page.goto(`${baseUrl}/repairs/rep-002`);
  await waitForApp();
  const awaabsSection = await page.locator('text=Awaab\'s Law Case').count();
  console.log(`   Awaab's Law section: ${awaabsSection > 0}`);
  await page.screenshot({ path: `${screenshotDir}/08-awaabs-law-repair.png`, fullPage: true });

  // 17. Test complaint detail with Link Repairs button
  console.log('\n13. Checking complaint detail page (cmp-001) Link Repairs...');
  await page.goto(`${baseUrl}/complaints/cmp-001`);
  await waitForApp();
  const linkRepairsBtn = await page.locator('text=Link Repairs').count();
  console.log(`   "Link Repairs" button: ${linkRepairsBtn > 0}`);
  await page.screenshot({ path: `${screenshotDir}/09-complaint-link-repairs.png`, fullPage: true });

  // 18. Click Link Repairs button to open modal
  if (linkRepairsBtn > 0) {
    await page.locator('text=Link Repairs').click();
    await page.waitForTimeout(500);
    await page.screenshot({ path: `${screenshotDir}/10-link-repairs-modal.png`, fullPage: true });
    const modalTitle = await page.locator('text=Select repairs').count();
    const checkboxes = await page.locator('input[type="checkbox"]').count();
    console.log(`   Modal opened: ${modalTitle > 0}`);
    console.log(`   Checkboxes for repairs: ${checkboxes}`);
  }

  // Summary
  console.log('\n=== TEST SUMMARY ===');
  console.log('Screenshots saved to test-screenshots/');
  console.log('All UI elements verified via DOM inspection.\n');

  await browser.close();
})();

